<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Customer Conversations</h1><p class="text-muted mb-0">Track portal, email, SMS, phone, and internal conversations in one place.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">New Conversation</h2><form method="post" action="/portal/conversations" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Customer</label><select name="customer_id" class="form-select" required><option value="">Select customer</option><?php foreach($customers as $c):?><option value="<?=$c['id']?>"><?=e($c['display_name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Subject</label><input name="subject" class="form-control" required></div><div class="col-6"><label class="form-label">Priority</label><select name="priority" class="form-select"><option>normal</option><option>high</option><option>urgent</option><option>low</option></select></div><div class="col-6"><label class="form-label">Channel</label><select name="channel" class="form-select"><option>portal</option><option>email</option><option>sms</option><option>phone</option><option>internal</option></select></div><div class="col-12"><label class="form-label">Assign To</label><select name="assigned_user_id" class="form-select"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Opening Message</label><textarea name="body" class="form-control" rows="4"></textarea></div><div class="col-12 form-check ms-2"><input class="form-check-input" type="checkbox" name="is_internal" id="internal"><label class="form-check-label" for="internal">Internal note only</label></div><div class="col-12"><button class="btn btn-primary w-100">Create Conversation</button></div></form></div></div></div>
<div class="col-xl-8"><div class="card shadow-sm"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Subject</th><th>Customer</th><th>Status</th><th>Assigned</th><th>Messages</th><th></th></tr></thead><tbody><?php foreach($threads as $t):?><tr><td><strong><?=e($t['subject'])?></strong><div class="small text-muted"><?=e($t['priority'])?> priority</div></td><td><?=e($t['customer_name'])?></td><td><span class="badge text-bg-<?=$t['status']==='closed'?'secondary':'primary'?>"><?=e($t['status'])?></span></td><td><?=e($t['assigned_name']??'Unassigned')?></td><td><?=$t['message_count']?></td><td><a class="btn btn-sm btn-outline-primary" href="/portal/conversations/<?=$t['id']?>">Open</a></td></tr><?php endforeach?><?php if(!$threads):?><tr><td colspan="6" class="text-center text-muted py-5">No conversations yet.</td></tr><?php endif?></tbody></table></div></div></div></div>
